internal_vs_canonical_shapes.ejemplo:
// shape interno del helper (privado)
const result = await this.deepseek.chatCompletion({ ... });
if (result.ok) {
  // traduccion a shape canonico antes de publicar al bus
  await this._publicarEvento('llm.complete.response', this._buildSuccessResponse({ status: 200, data: result.data }), payload);
} else {
  await this._publicarEvento('llm.complete.response', this._buildErrorResponse({
    status: result.error.status,
    code:   result.error.code,
    message: result.error.message,
    details: result.error.details
  }), payload);
}
